97	// Deep equality helper (explicit field walk, no PartialEq derive on Pack)
98	// ---------------------------------------------------------------------------
99	
100	fn assert_packs_equal(left: &Pack, right: &Pack) {
101	    assert_eq!(left.name, right.name, "pack.name mismatch");
102	    assert_eq!(left.author, right.author, "pack.author mismatch");
103	    assert_eq!(
104	        left.categories.len(),
105	        right.categories.len(),
106	        "pack.categories.len() mismatch: left={}, right={}",
107	        left.categories.len(),
108	        right.categories.len()
109	    );
110	
111	    for (i, (lcat, rcat)) in left.categories.iter().zip(right.categories.iter()).enumerate() {
112	        assert_eq!(
113	            lcat.name, rcat.name,
114	            "category[{}].name mismatch: '{}' vs '{}'",
115	            i, lcat.name, rcat.name
116	        );
117	        assert_eq!(
118	            lcat.macros.len(),
119	            rcat.macros.len(),
120	            "category[{}] ('{}') macro count mismatch",
121	            i,
122	            lcat.name
123	        );
124	
125	        for (j, (lm, rm)) in lcat.macros.iter().zip(rcat.macros.iter()).enumerate() {
126	            let loc = format!("category[{}]['{}'].macros[{}]", i, lcat.name, j);
127	            assert_eq!(lm.name, rm.name, "{}.name", loc);
128	            assert_eq!(lm.phrase, rm.phrase, "{}.phrase", loc);
129	            assert_eq!(lm.if_flag, rm.if_flag, "{}.if_flag", loc);
130	            assert_eq!(lm.set_flag, rm.set_flag, "{}.set_flag", loc);
131	            assert_eq!(lm.sound, rm.sound, "{}.sound", loc);
132	            assert_eq!(lm.keys.len(), rm.keys.len(), "{}.keys.len()", loc);
133	            for (k, (lk, rk)) in lm.keys.iter().zip(rm.keys.iter()).enumerate() {
134	                assert_eq!(lk.key, rk.key, "{}.keys[{}].key", loc, k);
135	                assert_eq!(lk.dwell_ms, rk.dwell_ms, "{}.keys[{}].dwell_ms", loc, k);
136	                assert_eq!(lk.gap_ms, rk.gap_ms, "{}.keys[{}].gap_ms", loc, k);
137	            }
138	        }
139	    }
140	}
