146	/// Full CRUD sequence: edit → save → reload → structural equality.
147	///
148	/// Exercises every PackEditor method in one sequence, then proves the
149	/// in-memory Pack and the reloaded Pack are structurally identical.
150	#[test]
151	fn roundtrip_after_full_crud_sequence() {
152	    let mut ed = PackEditor::new(starter_pack());
153	
154	    // 1. Add a new category
155	    ed.add_category("NewCat").expect("add_category must succeed");
156	
157	    // 2. Add a macro to the new category
158	    ed.add_macro(
159	        "NewCat",
160	        macro_simple("Eagle Airstrike", "eagle airstrike", vec![
161	            key("KEY_W"), key("KEY_D"), key("KEY_S"), key("KEY_D"),
162	        ]),
163	    )
164	    .expect("add_macro to NewCat must succeed");
165	
166	    // 3. Edit an existing macro in Stratagems
167	    ed.edit_macro(
168	        "Stratagems",
169	        "Reinforce",
170	        MacroUpdates {
171	            phrase: Some(Some("call for reinforce".to_string())),
172	            keys: Some(vec![key("KEY_W"), key("KEY_S"), key("KEY_W")]),
173	            ..Default::default()
174	        },
175	    )
176	    .expect("edit_macro must succeed");
177	
178	    // 4. Move a macro between categories
179	    ed.move_macro("Support", "Stratagems", "Clear Flag")
180	        .expect("move_macro must succeed");
181	
182	    // 5. Rename a category (in-place, preserving macros)
183	    ed.rename_category("NewCat", "Eagles").expect("rename_category must succeed");
184	
185	    // 6. Remove a macro to prepare for category removal
186	    ed.remove_macro("Eagles", "Eagle Airstrike")
187	        .expect("remove_macro must succeed");
188	
189	    // 7. Remove the now-empty category
190	    ed.remove_category("Eagles").expect("remove_category on empty category must succeed");
191	
192	    // Capture expected state before save
193	    let expected = ed.pack().clone();
194	
195	    // Save to tempdir and reload
196	    let dir = tempfile::tempdir().expect("tempdir must be created");
197	    expected.save_to_dir(dir.path()).expect("save_to_dir must succeed");
198	    let reloaded = Pack::load_from_dir(dir.path()).expect("load_from_dir must succeed");
199	
200	    assert_packs_equal(&expected, &reloaded);
201	}
