203	/// Byte-for-byte YAML stability: two saves of the same in-memory Pack must
204	/// produce identical bytes, guarding against serde_yaml_ng non-determinism.
205	#[test]
206	fn roundtrip_yaml_text_stable_within_run() {
207	    let mut ed = PackEditor::new(starter_pack());
208	
209	    // Apply a representative edit so the pack is non-trivial
210	    ed.add_category("Boosters").expect("add_category must succeed");
211	    ed.add_macro(
212	        "Boosters",
213	        macro_simple("Vitality Enhancement", "vitality enhancement", vec![key("KEY_V")]),
214	    )
215	    .expect("add_macro must succeed");
216	    ed.edit_macro(
217	        "Stratagems",
218	        "Resupply",
219	        MacroUpdates {
220	            phrase: Some(Some("drop resupply".to_string())),
221	            ..Default::default()
222	        },
223	    )
224	    .expect("edit_macro must succeed");
225	
226	    let pack = ed.into_pack();
227	
228	    let dir1 = tempfile::tempdir().expect("tempdir 1 must be created");
229	    let dir2 = tempfile::tempdir().expect("tempdir 2 must be created");
230	
231	    pack.save_to_dir(dir1.path()).expect("save to dir1 must succeed");
232	    pack.save_to_dir(dir2.path()).expect("save to dir2 must succeed");
233	
234	    let bytes1 = std::fs::read(dir1.path().join("pack.yaml"))
235	        .expect("reading dir1/pack.yaml must succeed");
236	    let bytes2 = std::fs::read(dir2.path().join("pack.yaml"))
237	        .expect("reading dir2/pack.yaml must succeed");
238	
239	    assert_eq!(
240	        bytes1, bytes2,
241	        "two saves of the same Pack must produce byte-identical YAML"
242	    );
243	}
