245	/// Verifies that all Option fields (phrase=None, if_flag=Some, set_flag=None,
246	/// dwell/gap overrides) survive a save → reload cycle exactly.
247	#[test]
248	fn roundtrip_preserves_optional_fields() {
249	    let pack = Pack {
250	        name: "OptionalFieldsTest".to_string(),
251	        author: None,
252	        categories: vec![Category {
253	            name: "Mixed".to_string(),
254	            macros: vec![
255	                // phrase=None, if_flag=Some, set_flag=None, no timing
256	                macro_optional(
257	                    "Silent Trigger",
258	                    None,
259	                    Some("some_flag"),
260	                    None,
261	                    vec![key("KEY_X")],
262	                ),
263	                // phrase=Some, if_flag=None, set_flag=None, timing on all keys
264	                macro_optional(
265	                    "Timed Action",
266	                    Some("timed action"),
267	                    None,
268	                    None,
269	                    vec![
270	                        key_timed("KEY_A", 150, 50),
271	                        key_timed("KEY_B", 200, 100),
272	                    ],
273	                ),
274	                // phrase=Some, set_flag=Some, mixed keys (some timed, some not)
275	                macro_optional(
276	                    "Flag Setter",
277	                    Some("set flag"),
278	                    None,
279	                    Some("result_flag"),
280	                    vec![key("KEY_W"), key_timed("KEY_S", 300, 200), key("KEY_D")],
281	                ),
282	                // no keys at all — valid edge case
283	                macro_optional("Empty Keys", Some("empty keys"), None, None, vec![]),
284	            ],
285	        }],
286	    };
287	
288	    // Apply a no-op edit: add then immediately remove a temporary macro.
289	    let mut ed = PackEditor::new(pack.clone());
290	    ed.add_macro(
291	        "Mixed",
292	        macro_simple("Temp", "temp", vec![key("KEY_T")]),
293	    )
294	    .expect("add temp macro must succeed");
295	    ed.remove_macro("Mixed", "Temp").expect("remove temp macro must succeed");
296	    let edited = ed.into_pack();
297	
298	    let dir = tempfile::tempdir().expect("tempdir must be created");
299	    edited.save_to_dir(dir.path()).expect("save_to_dir must succeed");
300	    let reloaded = Pack::load_from_dir(dir.path()).expect("load_from_dir must succeed");
301	
302	    assert_packs_equal(&edited, &reloaded);
303	
304	    // Extra explicit checks for Option fields
305	    let macros = &reloaded.categories[0].macros;
306	
307	    let silent = macros.iter().find(|m| m.name == "Silent Trigger").unwrap();
308	    assert_eq!(silent.phrase, None, "phrase must remain None");
309	    assert_eq!(silent.if_flag, Some("some_flag".to_string()), "if_flag must survive");
310	    assert_eq!(silent.set_flag, None, "set_flag must remain None");
311	
312	    let timed = macros.iter().find(|m| m.name == "Timed Action").unwrap();
313	    assert_eq!(timed.keys[0].dwell_ms, Some(150), "dwell_ms must survive");
314	    assert_eq!(timed.keys[0].gap_ms, Some(50), "gap_ms must survive");
315	    assert_eq!(timed.keys[1].dwell_ms, Some(200), "second key dwell_ms must survive");
316	
317	    let setter = macros.iter().find(|m| m.name == "Flag Setter").unwrap();
318	    assert_eq!(setter.set_flag, Some("result_flag".to_string()), "set_flag must survive");
319	    assert_eq!(setter.keys[0].dwell_ms, None, "untimed key dwell_ms must remain None");
320	    assert_eq!(setter.keys[1].dwell_ms, Some(300), "timed key dwell_ms must survive");
321	
322	    let empty = macros.iter().find(|m| m.name == "Empty Keys").unwrap();
323	    assert!(empty.keys.is_empty(), "empty keys vec must survive round-trip");
324	}
