456	/// Build a [`MacroConfig`] from raw form-field strings.
457	///
458	/// - `name` must be non-empty (after trim).
459	/// - `phrase`, `if_flag`, `set_flag` become `None` when empty.
460	/// - `keys` is parsed via [`parse_key_sequence`].
461	///
462	/// This is a pure function with no egui dependency — it is unit-tested directly.
463	pub fn build_macro_config_from_form(
464	    name: &str,
465	    phrase: &str,
466	    if_flag: &str,
467	    set_flag: &str,
468	    keys: &str,
469	) -> Result<MacroConfig, FormBuildError> {
470	    let name = name.trim().to_string();
471	    if name.is_empty() {
472	        return Err(FormBuildError::EmptyName);
473	    }
474	    let phrase = {
475	        let s = phrase.trim();
476	        if s.is_empty() { None } else { Some(s.to_string()) }
477	    };
478	    let if_flag = {
479	        let s = if_flag.trim();
480	        if s.is_empty() { None } else { Some(s.to_string()) }
481	    };
482	    let set_flag = {
483	        let s = set_flag.trim();
484	        if s.is_empty() { None } else { Some(s.to_string()) }
485	    };
486	    let keys = parse_key_sequence(keys).map_err(FormBuildError::KeyParseError)?;
487	
488	    Ok(MacroConfig { name, phrase, if_flag, set_flag, sound: None, keys })
489	}
