491	/// Parse a comma-separated key sequence string into a `Vec<KeyAction>`.
492	///
493	/// Each token is trimmed of whitespace and becomes a `KeyAction` with `dwell_ms`
494	/// and `gap_ms` left as `None` (inheriting global timing defaults).
495	/// Returns an error if the input is empty or any token is empty after trimming.
496	pub fn parse_key_sequence(input: &str) -> Result<Vec<KeyAction>> {
497	    if input.trim().is_empty() {
498	        bail!("key sequence must not be empty");
499	    }
500	
501	    let mut actions = Vec::new();
502	    for token in input.split(',') {
503	        let key = token.trim().to_string();
504	        if key.is_empty() {
505	            bail!("key sequence contains an empty token (check for trailing commas)");
506	        }
507	        actions.push(KeyAction { key, dwell_ms: None, gap_ms: None });
508	    }
509	
510	    Ok(actions)
511	}
